import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import { 
  Users, MessageCircle, Home, LogOut, Eye, 
  CheckCircle, Clock, AlertCircle, Trash2, 
  Edit, Plus, X, Search
} from 'lucide-react';

const AdminDashboard = () => {
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState('enquiries');
  const [enquiries, setEnquiries] = useState([]);
  const [properties, setProperties] = useState([]);
  const [loading, setLoading] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  useEffect(() => {
    // Check if admin is logged in
    const adminToken = localStorage.getItem('adminToken');
    if (!adminToken) {
      navigate('/admin/login');
      return;
    }
    loadMockData();
  }, [navigate]);

  const loadMockData = () => {
    // Mock enquiries data
    const mockEnquiries = [
      { 
        _id: '1', 
        name: 'Rahul Sharma', 
        email: 'rahul@example.com', 
        phone: '9876543210', 
        message: 'I am interested in Sunrise Heights apartment. Please share more details.', 
        interestedIn: 'Residential', 
        status: 'New', 
        createdAt: new Date().toISOString() 
      },
      { 
        _id: '2', 
        name: 'Priya Patel', 
        email: 'priya@example.com', 
        phone: '9876543211', 
        message: 'Looking for commercial space for my new office.', 
        interestedIn: 'Commercial', 
        status: 'In Progress', 
        createdAt: new Date(Date.now() - 86400000).toISOString() 
      },
      { 
        _id: '3', 
        name: 'Amit Kumar', 
        email: 'amit@example.com', 
        phone: '9876543212', 
        message: 'Is the 3 BHK flat still available?', 
        interestedIn: 'Residential', 
        status: 'Completed', 
        createdAt: new Date(Date.now() - 172800000).toISOString() 
      },
      { 
        _id: '4', 
        name: 'Neha Gupta', 
        email: 'neha@example.com', 
        phone: '9876543213', 
        message: 'Need information about payment plans.', 
        interestedIn: 'General', 
        status: 'New', 
        createdAt: new Date(Date.now() - 43200000).toISOString() 
      },
    ];
    
    // Mock properties data
    const mockProperties = [
      { _id: '1', title: 'Sunrise Heights', category: 'Residential', price: 4500000, status: 'Available', images: ['https://images.unsplash.com/photo-1560448204-e02f11c3d0e2?w=100'] },
      { _id: '2', title: 'Business Plaza', category: 'Commercial', price: 15000000, status: 'Available', images: ['https://images.unsplash.com/photo-1497366216548-37526070297c?w=100'] },
      { _id: '3', title: 'Green Valley Villas', category: 'Residential', price: 25000000, status: 'Sold', images: ['https://images.unsplash.com/photo-1560185127-6ed189bf02f4?w=100'] },
    ];
    
    setEnquiries(mockEnquiries);
    setProperties(mockProperties);
    setLoading(false);
  };

  const handleLogout = () => {
    localStorage.removeItem('adminToken');
    navigate('/admin/login');
  };

  const updateEnquiryStatus = (id, newStatus) => {
    setEnquiries(enquiries.map(e => e._id === id ? { ...e, status: newStatus } : e));
  };

  const deleteEnquiry = (id) => {
    if (window.confirm('Delete this enquiry?')) {
      setEnquiries(enquiries.filter(e => e._id !== id));
    }
  };

  const getStatusBadge = (status) => {
    switch(status) {
      case 'New': return <span className="flex items-center gap-1 bg-yellow-100 text-yellow-700 px-2 py-1 rounded-full text-xs"><Clock size={12} /> New</span>;
      case 'In Progress': return <span className="flex items-center gap-1 bg-blue-100 text-blue-700 px-2 py-1 rounded-full text-xs"><AlertCircle size={12} /> In Progress</span>;
      case 'Completed': return <span className="flex items-center gap-1 bg-green-100 text-green-700 px-2 py-1 rounded-full text-xs"><CheckCircle size={12} /> Completed</span>;
      default: return <span className="bg-gray-100 text-gray-700 px-2 py-1 rounded-full text-xs">New</span>;
    }
  };

  const filteredEnquiries = enquiries.filter(e => 
    e.name?.toLowerCase().includes(searchTerm.toLowerCase()) ||
    e.email?.toLowerCase().includes(searchTerm.toLowerCase()) ||
    e.phone?.includes(searchTerm)
  );

  const stats = {
    totalEnquiries: enquiries.length,
    newEnquiries: enquiries.filter(e => e.status === 'New').length,
    inProgress: enquiries.filter(e => e.status === 'In Progress').length,
    completed: enquiries.filter(e => e.status === 'Completed').length,
    totalProperties: properties.length,
  };

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-[#d4af37]"></div>
      </div>
    );
  }

  return (
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      className="min-h-screen bg-gray-100"
    >
      {/* Admin Navbar */}
      <nav className="bg-[#0a192f] text-white py-4 px-6 fixed top-0 w-full z-50">
        <div className="flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-[#d4af37] rounded-lg flex items-center justify-center">
              <span className="text-[#0a192f] font-bold text-xl">A</span>
            </div>
            <div>
              <span className="font-bold text-xl">Admin Dashboard</span>
              <p className="text-xs text-white/70">Swabhagya Realty</p>
            </div>
          </div>
          <button
            onClick={handleLogout}
            className="flex items-center gap-2 bg-red-500/20 px-4 py-2 rounded-lg hover:bg-red-500/30 transition"
          >
            <LogOut size={18} /> Logout
          </button>
        </div>
      </nav>

      <div className="pt-24 pb-8 px-6">
        <div className="container-custom">
          {/* Stats Cards */}
          <div className="grid grid-cols-1 md:grid-cols-4 gap-6 mb-8">
            <div className="bg-white rounded-xl shadow-md p-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-gray-500 text-sm">Total Enquiries</p>
                  <p className="text-3xl font-bold text-[#0a192f]">{stats.totalEnquiries}</p>
                </div>
                <MessageCircle size={40} className="text-[#d4af37] opacity-50" />
              </div>
            </div>
            <div className="bg-white rounded-xl shadow-md p-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-gray-500 text-sm">New Enquiries</p>
                  <p className="text-3xl font-bold text-yellow-600">{stats.newEnquiries}</p>
                </div>
                <Clock size={40} className="text-yellow-500 opacity-50" />
              </div>
            </div>
            <div className="bg-white rounded-xl shadow-md p-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-gray-500 text-sm">In Progress</p>
                  <p className="text-3xl font-bold text-blue-600">{stats.inProgress}</p>
                </div>
                <AlertCircle size={40} className="text-blue-500 opacity-50" />
              </div>
            </div>
            <div className="bg-white rounded-xl shadow-md p-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-gray-500 text-sm">Completed</p>
                  <p className="text-3xl font-bold text-green-600">{stats.completed}</p>
                </div>
                <CheckCircle size={40} className="text-green-500 opacity-50" />
              </div>
            </div>
          </div>

          {/* Tabs */}
          <div className="bg-white rounded-xl shadow-md overflow-hidden">
            <div className="flex border-b">
              <button
                onClick={() => setActiveTab('enquiries')}
                className={`px-6 py-3 font-semibold transition flex items-center gap-2 ${
                  activeTab === 'enquiries' 
                    ? 'text-[#d4af37] border-b-2 border-[#d4af37]' 
                    : 'text-gray-500 hover:text-[#0a192f]'
                }`}
              >
                <MessageCircle size={18} /> Enquiries ({stats.totalEnquiries})
              </button>
              <button
                onClick={() => setActiveTab('properties')}
                className={`px-6 py-3 font-semibold transition flex items-center gap-2 ${
                  activeTab === 'properties' 
                    ? 'text-[#d4af37] border-b-2 border-[#d4af37]' 
                    : 'text-gray-500 hover:text-[#0a192f]'
                }`}
              >
                <Home size={18} /> Properties ({stats.totalProperties})
              </button>
            </div>

            {/* Search Bar */}
            <div className="p-4 border-b">
              <div className="relative max-w-sm">
                <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" size={18} />
                <input
                  type="text"
                  placeholder="Search enquiries..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  className="w-full pl-10 pr-3 py-2 border rounded-lg focus:outline-none focus:border-[#d4af37]"
                />
              </div>
            </div>

            {/* Enquiries Tab */}
            {activeTab === 'enquiries' && (
              <div className="overflow-x-auto">
                <table className="w-full">
                  <thead className="bg-gray-50">
                    <tr>
                      <th className="p-3 text-left text-sm font-semibold">Date</th>
                      <th className="p-3 text-left text-sm font-semibold">Name</th>
                      <th className="p-3 text-left text-sm font-semibold">Contact</th>
                      <th className="p-3 text-left text-sm font-semibold">Interested In</th>
                      <th className="p-3 text-left text-sm font-semibold">Message</th>
                      <th className="p-3 text-left text-sm font-semibold">Status</th>
                      <th className="p-3 text-left text-sm font-semibold">Actions</th>
                    </tr>
                  </thead>
                  <tbody>
                    {filteredEnquiries.map((enquiry) => (
                      <tr key={enquiry._id} className="border-t hover:bg-gray-50">
                        <td className="p-3 text-sm">{new Date(enquiry.createdAt).toLocaleDateString()}</td>
                        <td className="p-3 font-medium">{enquiry.name}</td>
                        <td className="p-3 text-sm">
                          <div>{enquiry.email}</div>
                          <div className="text-xs text-gray-500">{enquiry.phone}</div>
                        </td>
                        <td className="p-3 text-sm">{enquiry.interestedIn || 'General'}</td>
                        <td className="p-3 text-sm max-w-xs truncate">{enquiry.message}</td>
                        <td className="p-3">
                          <select
                            value={enquiry.status || 'New'}
                            onChange={(e) => updateEnquiryStatus(enquiry._id, e.target.value)}
                            className="text-sm border rounded-lg px-2 py-1"
                          >
                            <option value="New">New</option>
                            <option value="In Progress">In Progress</option>
                            <option value="Completed">Completed</option>
                          </select>
                        </td>
                        <td className="p-3">
                          <button
                            onClick={() => deleteEnquiry(enquiry._id)}
                            className="text-red-500 hover:text-red-700"
                          >
                            <Trash2 size={18} />
                          </button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
                {filteredEnquiries.length === 0 && (
                  <div className="text-center py-12">
                    <p className="text-gray-500">No enquiries found</p>
                  </div>
                )}
              </div>
            )}

            {/* Properties Tab */}
            {activeTab === 'properties' && (
              <div>
                <div className="p-4 border-b flex justify-between items-center">
                  <h3 className="font-semibold">Property List</h3>
                  <button className="flex items-center gap-2 bg-[#d4af37] text-[#0a192f] px-3 py-1.5 rounded-lg text-sm font-semibold">
                    <Plus size={16} /> Add Property
                  </button>
                </div>
                <div className="overflow-x-auto">
                  <table className="w-full">
                    <thead className="bg-gray-50">
                      <tr>
                        <th className="p-3 text-left text-sm font-semibold">Image</th>
                        <th className="p-3 text-left text-sm font-semibold">Title</th>
                        <th className="p-3 text-left text-sm font-semibold">Category</th>
                        <th className="p-3 text-left text-sm font-semibold">Price</th>
                        <th className="p-3 text-left text-sm font-semibold">Status</th>
                        <th className="p-3 text-left text-sm font-semibold">Actions</th>
                      </tr>
                    </thead>
                    <tbody>
                      {properties.map((property) => (
                        <tr key={property._id} className="border-t hover:bg-gray-50">
                          <td className="p-3">
                            <img src={property.images?.[0] || 'https://via.placeholder.com/50'} alt="" className="w-12 h-12 object-cover rounded" />
                          </td>
                          <td className="p-3 font-medium">{property.title}</td>
                          <td className="p-3 text-sm">{property.category}</td>
                          <td className="p-3 text-sm">₹{(property.price / 100000).toFixed(1)}L</td>
                          <td className="p-3">
                            <span className={`px-2 py-1 rounded-full text-xs ${property.status === 'Available' ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
                              {property.status}
                            </span>
                          </td>
                          <td className="p-3">
                            <div className="flex gap-2">
                              <button className="text-blue-500 hover:text-blue-700"><Edit size={18} /></button>
                              <button className="text-red-500 hover:text-red-700"><Trash2 size={18} /></button>
                            </div>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </motion.div>
  );
};

export default AdminDashboard;
